const items = $input.all().map(i => i.json);

// Expensive items need tighter threshold (3x reorder level)
const expensiveItems = ['Guacamole','Protein Plus','Parmesan','Matcha Mix','Almond'];

const lowStock = items.filter(item => {
  const multiplier = expensiveItems.some(e => (item.name||'').includes(e)) ? 3 : 1;
  return parseFloat(item.quantity||0) <= parseFloat(item.reorder_level||0) * multiplier;
});

if (lowStock.length === 0) return [];

const today = new Date().toLocaleDateString('en-IN', {day:'2-digit',month:'short'});

const critical = lowStock.filter(i => parseFloat(i.quantity||0) <= parseFloat(i.reorder_level||0));
const warning = lowStock.filter(i => parseFloat(i.quantity||0) > parseFloat(i.reorder_level||0));

let msg = `*Nubo Inventory Alert — ${today}*\n`;

if (critical.length > 0) {
  msg += `\n🔴 *Critical (below reorder level)*\n`;
  msg += critical.map(i => `• ${i.name}: ${i.quantity}${i.unit} (min: ${i.reorder_level}${i.unit})`).join('\n');
}

if (warning.length > 0) {
  msg += `\n\n🟡 *Low stock (order soon)*\n`;
  msg += warning.map(i => `• ${i.name}: ${i.quantity}${i.unit}`).join('\n');
}

msg += `\n\nAction: Contact Om Sai or check alternates`;

return [{ json: { message: msg, criticalCount: critical.length, warningCount: warning.length } }];
